import functools

# Simulate a global session and user store
session = {}
users = {1: {"id": 1, "name": "Alice", "email": "alice@example.com"}}

def login_required(func):
    """Decorator that protects a route function."""
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        # TODO: Check if 'user_id' is in session
        # If not: print "Redirecting to /login" and return None
        # If yes: get the user dict and call func(user, *args, **kwargs)
        pass
    return wrapper

# Define some 'route' functions
@login_required
def dashboard(user):
    print(f"Dashboard: Welcome, {user['name']}!")

@login_required
def profile(user):
    print(f"Profile: {user['name']} ({user['email']})")

def home():
    print("Home: Public page")

# Test 1: Not logged in
print("--- Not logged in ---")
home()
dashboard()
profile()

# Test 2: Log in
print("--- Logged in ---")
session["user_id"] = 1
home()
dashboard()
